void GANModel::generate(const float* z, float* out) {
    // Copy z into working buffer
    for (int k = 0; k < 16; k++) buf_a[k] = z[k];
    float* src = buf_a;
    float* dst = buf_b;

    // Block 0: linear 16→128  act=relu  bn=True  cond=False
    for (int k = 0; k < 128; k++) {
        float acc = gen0_b[k];
        for (int j = 0; j < 16; j++)
            acc += gen0_W[k][j] * src[j];
        float rmean = gen0_bn_rmean[k];
        float rvar  = gen0_bn_rvar[k];
        float gamma = gen0_bn_gamma[k];
        float beta  = gen0_bn_beta[k];
        acc = gamma * (acc - rmean) / sqrtf(rvar + 1e-5f) + beta;
        if (acc < 0.0f) acc = 0.0f;
        dst[k] = acc;
    }
    { float* tmp = src; src = dst; dst = tmp; }

    // Block 1: linear 128→256  act=relu  bn=True  cond=False
    for (int k = 0; k < 256; k++) {
        float acc = gen1_b[k];
        for (int j = 0; j < 128; j++)
            acc += gen1_W[k][j] * src[j];
        float rmean = gen1_bn_rmean[k];
        float rvar  = gen1_bn_rvar[k];
        float gamma = gen1_bn_gamma[k];
        float beta  = gen1_bn_beta[k];
        acc = gamma * (acc - rmean) / sqrtf(rvar + 1e-5f) + beta;
        if (acc < 0.0f) acc = 0.0f;
        dst[k] = acc;
    }
    { float* tmp = src; src = dst; dst = tmp; }

    // Block 2: linear 256→4  act=tanh  bn=False  cond=False
    for (int k = 0; k < 4; k++) {
        float acc = gen2_b[k];
        for (int j = 0; j < 256; j++)
            acc += gen2_W[k][j] * src[j];
        acc = tanhf(acc);
        out[k] = acc;
    }
}